const LON_MIN = 25.665136337280273
const LAT_MAX = 42.1054115295413
const COS_LAT = 0.7775805256021876
const SCALE = 63.5931497827001
const PAD = 20

export function projectLonLat(lon: number, lat: number): { x: number; y: number } {
  return {
    x: PAD + (lon - LON_MIN) * COS_LAT * SCALE,
    y: PAD + (LAT_MAX - lat) * SCALE,
  }
}